import type { BaseStats, SlotKind, RarityId } from './types';

export interface ClassSkillDef {
  id: string;
  name: string;
  icon: string;
  unlockLevel: number;
  maxRank: number;
  manaCost: number;
  cooldown: number;
  desc: string;
  color: string;
}

export interface ClassTalentDef {
  id: string;
  name: string;
  icon: string;
  branchId: string;
  row: number;
  maxRank: number;
  desc: string;
  per: (rank: number) => string;
}

export interface ClassBranchDef {
  id: string;
  name: string;
  icon: string;
  color: string;
  desc: string;
}

export interface StarterItemDef {
  name: string;
  slot: SlotKind;
  rarity: RarityId;
  icon: string;
  dmg?: number;
  armor?: number;
  hp?: number;
}

export interface HeroClassDef {
  id: string;
  name: string;
  title: string;
  icon: string;
  artSrc?: string;
  color: string;
  desc: string;
  lore: string;
  baseStats: BaseStats;
  starterGear: StarterItemDef[];
  branches: ClassBranchDef[];
  talents: ClassTalentDef[];
  skills: ClassSkillDef[];
}

